function logMiaContractDebug(contract = {}) {
  console.log("🧠 MIA LLM CONTRACT:", {
    role: contract.role || "general_reply",
    intent: contract.intent || "",
    provider: contract.options?.provider || MIA_LLM_PROVIDER,
    model: contract.options?.model || MIA_TEXT_MODEL,
    temperature: contract.options?.temperature ?? null,
    max_tokens: contract.options?.max_tokens ?? null,
    metadata: contract.metadata || {},
    messageCount: Array.isArray(contract.messages) ? contract.messages.length : 0
  });
}

function validateMiaLLMContract(contract = {}) {
  const safeContract = {
    ...contract,
    role: contract.role || "general_reply",
    intent: contract.intent || "",
    messages: Array.isArray(contract.messages) ? contract.messages : [],
    options: {
      temperature: contract.options?.temperature ?? 0.4,
      max_tokens: contract.options?.max_tokens ?? 400,
      model: contract.options?.model || MIA_TEXT_MODEL,
      provider: contract.options?.provider || MIA_LLM_PROVIDER
    },
    metadata: contract.metadata || buildMiaContractMetadata()
  };

  return safeContract;
}

function buildMiaLLMContract({
  role = "general_reply",
  intent = "",
  messages = [],
  temperature = 0.4,
  max_tokens = 400,
  model = null,
  provider = MIA_LLM_PROVIDER,
  metadata = {}
} = {}) {
  const normalizedMetadata = buildMiaContractMetadata(metadata);

  const resolvedRole = resolveMiaRoleFromIntent({
    role,
    intent,
    metadata: normalizedMetadata
  });

  return {
    role: resolvedRole,
    intent,
    messages: Array.isArray(messages) ? messages : [],
    options: {
      temperature,
      max_tokens,
      model,
      provider
    },
    metadata: normalizedMetadata
  };
}

