    const secondScore = getValidScore(secondData, key);

    if (bestScore === null || secondScore === null) return "";

    const diff = bestScore - secondScore;
    const label = scoreLabels[key] || key;

    if (Math.abs(diff) <= 3) {
      return `Em ${label}, os dois ficam muito próximos: ${bestTitle} marca ${bestScore} e ${secondTitle} marca ${secondScore}.`;
    }

