        (await getProductSpecsFromSupabase(product.product_name || ""));

      const scoreEngine = buildScoreEngineFromSpecs(specs);

      const scores = scoreEngine?.scores || {};

      const priorityScore =
        priorityForFinalScore
          ? getScoreEngineValue(scoreEngine, priorityForFinalScore)
          : null;

      const generalScoreValues = [
        scores.performance,
        scores.camera,
        scores.battery,
        scores.screen,
        scores.longevity,
        scores.value
      ].filter((value) => value !== null && value !== undefined);

      const generalScore =
        generalScoreValues.length
          ? generalScoreValues.reduce((sum, value) => sum + Number(value), 0) / generalScoreValues.length
          : 0;

      const finalScore =
        priorityScore !== null && priorityScore !== undefined
          ? Number(priorityScore) * 1000
          : generalScore * 100;
